const express = require('express');
const crypto = require('crypto');
const app = express();

app.use(express.json());

app.post('/webhooks/orders', (req, res) => {
  // 1. Responda 200 imediatamente
  res.status(200).json({ received: true });

  // 2. Processe de forma assíncrona
  processEventAsync(req.body, req.headers)
    .catch(err => console.error('Webhook processing error:', err));
});

async function processEventAsync(payload, headers) {
  const signature = headers['x-webhook-signature'];
  const secret = process.env.WEBHOOK_SECRET;

  // 3. Valide a assinatura
  const isValid = validateSignature(payload, signature, secret);
  if (!isValid) throw new Error('Invalid signature');

  // 4. Verifique idempotência
  const eventId = payload.event_id;
  if (await isAlreadyProcessed(eventId)) return;

  // 5. Processe o evento
  if (payload.event === 'order.created') {
    await handleNewOrder(payload.data.order);
  }

  // 6. Marque como processado
  await markAsProcessed(eventId);
}

const crypto = require('crypto');

function validateSignature(payload, signatureHeader, secret) {
  // Compute expected signature
  const body = typeof payload === 'string'
    ? payload
    : JSON.stringify(payload);

  const expected = 'sha256=' + crypto
    .createHmac('sha256', secret)
    .update(body)
    .digest('hex');

  // Use constant-time comparison to prevent timing attacks
  try {
    return crypto.timingSafeEqual(
      Buffer.from(expected),
      Buffer.from(signatureHeader)
    );
  } catch {
    return false;
  }
}
